 19→ */
 20→class Stakeholder
 21→{
 22→    public const NAMES = [
 23→        WorkflowRequestStakeholder::REQUESTER_TYPE => '申请人',
 24→        WorkflowRequestStakeholder::DIRECT_SUPERVISOR_TYPE => '直接主管',
 25→        WorkflowRequestStakeholder::SUPERVISOR_TYPE => '部门主管',
 26→        WorkflowRequestStakeholder::SSC_TYPE => '部门SSC',
 27→    ];
 28→
 29→    public const CN_MISSING_ID_ERR_FORMAT = '您暂无%s，请联系小兰维护后再进行申请';
 30→
 31→    protected const RK_DATA = Stakeholder::class.'__DATA__';
 32→
 33→    public static $cachedUserIds = [];
 34→
 35→    /**
 36→     * 获取 Sfuser id 对应的直接主管，部门主管，SSC 等 sfuser id。
 37→     *
 38→     * @param int $sfuserId
 39→     * @param string $type
 40→     * @throws Exception
 41→     * @return mixed
 42→     */
 43→    public static function fetchSfuserIdViaFixedType(int $sfuserId, string $type = WorkflowRequestStakeholder::REQUESTER_TYPE)
 44→    {
 45→        if (empty(static::$cachedUserIds) || !array_key_exists($sfuserId, static::$cachedUserIds)) {
 46→            // 从 DB 中获取
 47→            $sfuser = Sfuser::findOrFail($sfuserId);
 48→            $data[WorkflowRequestStakeholder::REQUESTER_TYPE] = $sfuser->id;
 49→            $data[WorkflowRequestStakeholder::DIRECT_SUPERVISOR_TYPE] = $sfuser->direct_supervisor_id;
 50→            $data[WorkflowRequestStakeholder::SUPERVISOR_TYPE] = $sfuser->supervisor_id;
 51→            /** @var JobDepartment $jobDepartment */
 52→            $jobDepartment = JobDepartment::where('department_id', $sfuser->department_id)->firstOrFail();
 53→            $data[WorkflowRequestStakeholder::SSC_TYPE] = $jobDepartment->ssc_id;
 54→            static::$cachedUserIds[$sfuserId] = $data;
 55→        }
 56→
 57→        if (static::$cachedUserIds[$sfuserId][$type] <= 0) {
 58→            // TODO-MSG: 您暂无直接主管，请联系小兰维护后再进行申请/您暂无部门主管，请联系小兰维护后再进行申请/您所在的部门暂无SSC，请联系小兰维护后再进行申请
 59→            throw new WorkflowException(sprintf(self::CN_MISSING_ID_ERR_FORMAT, static::NAMES[$type]));
 60→        }
 61→
 62→        return static::$cachedUserIds[$sfuserId][$type];
 63→    }
