 65→    /**
 66→     * 获取当前审批相关的人的 ID，直接获取即可，任何发起了的审批都只能走该方法获取对应的 ids，注意是 ids，获取固定或者特殊花名的两个方法
 67→     * 只用于流程创建的时候使用，找不到对应类型的人，代表流程发生了更新，直接报错，为了保证历史数据不出错，需要写一个处理历史数据的脚本。
 68→     * 该历史脚本只需在测试服和预发布上运行，因为正式服当前（2021年11月23日）只更新了餐补流程，无需执行对应的脚本。
 69→     *
 70→     * @param string $type
 71→     * @param int $requestId
 72→     * @param bool $onlyFirstElem
 73→     * @param bool $throwExp
 74→     * @throws WorkflowException
 75→     * @return mixed
 76→     */
 77→    public static function fetchSfuserIdsViaType(string $type, int $requestId, bool $onlyFirstElem = true, bool $throwExp = true)
 78→    {
 79→        /** @var WorkflowRequestAction $wra */
 80→        $wra = WorkflowRequestAction::where('operator_type', $type)->where('request_id', $requestId)
 81→            ->first();
 82→        $retIds = [];
 83→        if ($wra) {
 84→            $operatorId = $wra->operator_id;
 85→            // 操作者表中未找到
 86→            if ($operatorId) {
 87→                $retIds[$type] = Arr::wrap($operatorId);
 88→            }
 89→        }
 90→
 91→        if (!$retIds) {
 92→            // 仍然为空，查找 data 中保存的 ccs
 93→            /** @var WorkflowRequest $wr */
 94→            $wr = WorkflowRequest::findOrFail($requestId);
 95→            $data = $wr->data;
 96→            $users = array_merge(Arr::get($data, WorkflowRequest::SEE_TAGS_KEY), Arr::get($data, WorkflowRequest::CCS_KEY));
 97→            $retIds = Arr::only($users, $type);
 98→        }
 99→
100→        // 找不到直接报错，说明该流程定义发生了变化，新的流程定义会
101→        if ($throwExp && !$retIds) {
102→            // TODO-MSG: 流程无法正常流转，请尝试发起新的流程或联系管理员
103→            throw new WorkflowException('流程无法正确流转，请通知申请人撤回并删除本流程之后再发起一个新的流程。');
104→        }
105→        $retIds = Arr::get($retIds, $type, []);
106→        return $onlyFirstElem ? Arr::first($retIds) : $retIds;
107→    }
