226→                        } else {
227→                            throw new WorkflowException('请联系管理员配置【测试外派打车费审批人员-大黑帮】后再操作');
228→                        }
229→                    }
230→                }
231→            }
232→            if (array_key_exists('department', $context)) {
233→                if ($context['department'] === 16) {
234→                    $wr = WorkflowSpecialStakeholder::where(
235→                        'type',
236→                        WorkflowRequestStakeholder::REIMBURSEMENT_TEST_EXPAT_SUPERVISOR_HD_TYPE
237→                    )->first();
238→                    if ($wr) {
