489→    /**
490→     * 检查参与者是否存在，存在的话返回相关参与者，不存在的话会抛出一个异常。
491→     *
492→     * @throws Exception
493→     */
494→    public static function checkStakeholders(array $input, int $sfuserId, int $version = 0): array
495→    {
496→        if ($version <= 0) {
497→            $version = Helper::getWorkflowVersion($input['process_key']);
498→        }
499→
500→        $stateClassName = Registry::STATE_MAPS[$input['process_key']]['class'];
501→        switch ($input['process_key']) {
502→            case Registry::CROSS_ACCESS:
503→                $sc = new $stateClassName($version, Arr::get($input['context'], 'target_project'));
504→                break;
505→            case Registry::SUPPLEMENT:
506→                $sc = new $stateClassName($version, Arr::get($input['context'], 'request_id', -1));
507→                break;
508→            default:
509→                $sc = new $stateClassName($version);
510→                break;
511→        }
512→
513→        $stakeholders = [];
514→        foreach ($sc->actionRoles as $actions) {
515→            foreach ($actions as $operatorType) {
516→                if (!in_array($operatorType, WorkflowRequestStakeholder::FIXED_MAPS) && !isset($stakeholders[$operatorType])) {
517→                    $stakeholders[$operatorType] = Stakeholder::fetchSpecialSfuserId($operatorType, $sfuserId, $input['context']);
518→                }
519→            }
520→        }
521→        foreach ($sc->ccs as $ccs) {
522→            foreach ($ccs as $ccType) {
523→                if (!in_array($ccType, WorkflowRequestStakeholder::FIXED_MAPS) && !isset($stakeholders[$ccType])) {
524→                    $stakeholders[$ccType] = Stakeholder::fetchSpecialSfuserId($ccType, $sfuserId, $input['context']);
525→                }
526→            }
527→        }
528→        return $stakeholders;
529→    }
