$processKeyToExecutorTypeMap = [
    Registry::P4V_ACCESS => WorkflowRequestStakeholder::P4V_EXECUTER_TYPE,
    Registry::ONLY_OFFICE => WorkflowRequestStakeholder::ONLY_OFFICE_EXECUTOR_TYPE,
    Registry::JIRA_CONFLUENCE => WorkflowRequestStakeholder::JIRA_CONFLUENCE_EXECUTOR_TYPE,
    Registry::EB => WorkflowRequestStakeholder::EB_EXECUTOR_TYPE,
    Registry::YA => WorkflowRequestStakeholder::YA_EXECUTOR_TYPE,
    Registry::X_JIRA_CONFLUENCE => WorkflowRequestStakeholder::X_JIRA_CONFLUENCE_EXECUTOR_TYPE,
    Registry::AI_TOOLS => WorkflowRequestStakeholder::AI_TOOLS_EXECUTOR_TYPE,
    Registry::GCP => WorkflowRequestStakeholder::GCP_EXECUTOR_TYPE,
    Registry::MATTERMOST => WorkflowRequestStakeholder::MATTERMOST_EXECUTOR_TYPE,
];

foreach ($processKeyToExecutorTypeMap as $processKey => $executorType) {
    if ($input['process_key'] == Registry::JIRA_CONFLUENCE) {
        $dynamicNicknames1 = Stakeholder::specialNicknames(
            [WorkflowRequestStakeholder::JIRA_CONFLUENCE_EXECUTOR_TYPE],
            $input['sfuser_info']['id'],
            $input['context']
        );
        $dynamicNicknames2 = Stakeholder::specialNicknames(
            [WorkflowRequestStakeholder::X_JIRA_CONFLUENCE_EXECUTOR_TYPE],
            $input['sfuser_info']['id'],
            $input['context']
        );
        if (!isset($dynamicNicknames1['jira_confluence_executor'])) {
            throw new WorkflowException('请联系管理员配置【Jira/Confluence执行人】后再操作');
        }
        if (!isset($dynamicNicknames2['jira_confluence_executor'])) {
            throw new WorkflowException('请联系管理员配置【X项目Jira/Confluence执行人】后再操作');
        }
        $mergedNicknames = array_merge(
            $dynamicNicknames1['jira_confluence_executor'],
            $dynamicNicknames2['jira_confluence_executor']
        );
        $uniqueNicknames = array_unique($mergedNicknames);
        $data['dynamic_nicknames'] = [
            'jira_confluence_executor' => array_values($uniqueNicknames),
        ];
        break;

